// Competitor channels to watch (edit this list).
const channels = ['REPLACE_WITH_CHANNEL_1', 'REPLACE_WITH_CHANNEL_2', 'REPLACE_WITH_CHANNEL_3'];
return channels.map((c) => ({ json: { channel: c } }));

// Alert on recent videos whose titles match launch keywords (deduped across runs via static data).
const KEYWORDS = ['launch', 'release', 'announc', 'introducing', 'unveil', 'available now', 'drops', 'reveal', 'first look', 'new '];
const WINDOW_DAYS = 2; const cutoff = Date.now() - WINDOW_DAYS * 864e5;
function matched(t) { const s = (t || '').toLowerCase(); return KEYWORDS.find((k) => s.includes(k)) || null; }
const store = $getWorkflowStaticData('global'); store.seen = store.seen || [];
const seen = new Set(store.seen);
const launches = [];
for (const item of $input.all()) {
  const d = item.json; const ch = (d.channel && d.channel.title) || null;
  for (const v of (d.results || [])) {
    const pub = v.published ? new Date(v.published).getTime() : 0;
    const kw = matched(v.title);
    if (kw && pub >= cutoff && !seen.has(v.videoId)) {
      seen.add(v.videoId);
      launches.push({ channelTitle: ch, title: v.title, videoUrl: v.link || ('https://www.youtube.com/watch?v=' + v.videoId), matchedKeyword: kw.trim() });
    }
  }
}
store.seen = Array.from(seen).slice(-500);
if (launches.length === 0) return [];
const text = launches.map((l) => '• *' + (l.channelTitle || 'channel') + '*: ' + l.title + ' (' + l.matchedKeyword + ')\n' + l.videoUrl).join('\n\n');
return [ { json: { count: launches.length, launches, text } } ];
